import java.io.*;
import java.util.*;

import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly output sanitized user input
        System.out.println("<p>Welcome, " + sanitizedInput + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
